python3 -c "
import yaml
agents = yaml.safe_load(open('contracts/agent-tools.yaml'))
catalog = yaml.safe_load(open('contracts/event-catalog.yaml'))
catalog_types = {e['type'] for e in catalog.get('events', [])}
missing = []
for a in agents.get('agents', []):
  for evt in a.get('emit_events', []):
    if evt not in catalog_types:
      missing.append(f\"{a['id']}: {evt}\")
assert len(missing) == 0, f'Emit events missing from catalog: {missing}'
print('All emit_events have catalog entries')
"

